import{_ as a,o as r,c as i,ak as o}from"./chunks/framework.Bi-31Ycc.js";const u=JSON.parse('{"title":"Teacher Registration","description":"High-level overview of teacher onboarding and verification across Punjab Educare apps.","frontmatter":{"title":"Teacher Registration","description":"High-level overview of teacher onboarding and verification across Punjab Educare apps."},"headers":[],"relativePath":"punjab-educare/teacher-registration.md","filePath":"punjab-educare/teacher-registration.md","lastUpdated":1772239018000}'),t={name:"punjab-educare/teacher-registration.md"};function s(n,e,l,d,c,p){return r(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="teacher-registration" tabindex="-1">Teacher Registration <a class="header-anchor" href="#teacher-registration" aria-label="Permalink to “Teacher Registration”">​</a></h1><p>Teacher registration is available on both <strong>mobile</strong> and <strong>desktop</strong> apps and follows a guided onboarding flow designed for identity validation and platform quality control.</p><div class="warning custom-block"><p class="custom-block-title">Access</p><p>Teacher accounts are intended for real educators; registration is verified before teacher tools are fully unlocked.</p></div><h2 id="registration-flow" tabindex="-1">Registration Flow <a class="header-anchor" href="#registration-flow" aria-label="Permalink to “Registration Flow”">​</a></h2><ol><li><p><strong>School verification</strong><br> The teacher searches for their school and confirms the correct match (UDISE-based lookup).</p></li><li><p><strong>Profile details</strong><br> Basic details such as full name, email address, and phone number are collected for account setup and communication.</p></li><li><p><strong>Verification</strong><br> An OTP-based verification step is used during onboarding. Valid email is required for OTP verification.</p></li><li><p><strong>Identity &amp; eligibility</strong><br> Teachers are requested to upload a <strong>latest, clear</strong> copy of an identity document:</p><ul><li><strong>ePunjab ID</strong> (where available), or</li><li><strong>Aadhaar card</strong> (commonly used for private schools where ePunjab IDs may not exist).</li></ul></li></ol><div class="info custom-block"><p class="custom-block-title">ID document handling</p><p>Uploaded ID documents are used for verification purposes only and are deleted after teacher details are verified.</p></div><ol start="5"><li><strong>Submission and validation</strong><br> The registration is submitted for internal validation before teacher-only functionality becomes available.</li></ol><h2 id="guides" tabindex="-1">Guides <a class="header-anchor" href="#guides" aria-label="Permalink to “Guides”">​</a></h2><h3 id="mobile-apps" tabindex="-1">Mobile Apps <a class="header-anchor" href="#mobile-apps" aria-label="Permalink to “Mobile Apps”">​</a></h3><ul><li>Video walkthrough: <a href="https://youtu.be/ec-kTosDSnU" target="_blank" rel="noreferrer">YouTube</a></li><li>PDF guide: <a href="https://drive.google.com/open?id=1V5P574XPvjctu4jk12mbJPvmeDi23Qme&amp;usp=drive_fs" target="_blank" rel="noreferrer">Google Drive</a></li></ul><h3 id="desktop-apps" tabindex="-1">Desktop Apps <a class="header-anchor" href="#desktop-apps" aria-label="Permalink to “Desktop Apps”">​</a></h3><p><em>Coming soon</em></p>',12)])])}const g=a(t,[["render",s]]);export{u as __pageData,g as default};
